// Ejemplo de Starter en pom.xml
<dependency>
    <groupId>org.springframework.boot</groupId>
    <artifactId>spring-boot-starter-web</artifactId>
</dependency>

// Esto incluye automáticamente:
// - Tomcat embebido
// - Spring MVC
// - Jackson para JSON
// - Validación

// Clase main auto-generada por Spring Starter Project
package com.example.demo;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class DemoApplication {
    public static void main(String[] args) {
        SpringApplication.run(DemoApplication.class, args);
    }
}

// Sin Lombok - código manual extenso
public class Customer {
    private String code;
    private String name;

    public String getCode() { return code; }
    public void setCode(String code) { this.code = code; }
    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
}

// Con Lombok - código reducido
import lombok.Data;

@Data
public class Customer {
    private String code;
    private String name;
    // Getters, setters, toString, equals generados automáticamente
}
